1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Empty / trivial quote ---
6	  it("quote with empty item list returns premium 5 G (only processing fee)", () => {
7	    const result = processScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Single item base premiums (with newcomer first-insurance and fee folded in) ---
15	  it("quote for single plain sword (newcomer, 0 years) returns premium 115 G (100 base + 10 first-insurance + 5 fee)", () => {
16	    const result = processScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [
19	        {
20	          op: "quote",
21	          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
22	        },
23	      ],
24	    });
25	    expect(result).toEqual({ results: [{ premium: 115 }] });
26	  });
27	  it("quote for single plain amulet (newcomer) returns premium 71 G (60 base + 6 first-insurance + 5 fee)", () => {
28	    const result = processScenario({
29	      customer: { yearsWithMHPCO: 0 },
30	      steps: [
31	        {
32	          op: "quote",
33	          items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }],
34	        },
35	      ],
36	    });
37	    expect(result).toEqual({ results: [{ premium: 71 }] });
38	  });
39	  it.todo("quote for single plain staff (newcomer) returns premium 93 G (80 base + 8 first-insurance + 5 fee)");
40	  it.todo("quote for single plain potion (newcomer) returns premium 49 G (40 base + 4 first-insurance + 5 fee)");
41	
42	  // --- Component base premiums (building block of 3) ---
43	  it.todo("quote for 2 runes returns base premium 50 G before policy-wide modifiers (50 + 5 first-insurance + 5 fee = 60 G)");
44	  it.todo("quote for 3 runes applies block: base premium 60 G (60 + 6 first-insurance + 5 fee = 71 G)");
45	  it.todo("quote for 4 runes returns base premium 100 G — no block since block requires exactly 3 (100 + 10 first-insurance + 5 fee = 115 G)");
46	  it.todo("quote for 7 runes returns base premium 175 G (one block of 3 = 60 G + 4 runes × 25 G = 100 G; 175 + 18 first-insurance + 5 fee = 198 G)");
47	
48	  // --- 'Alike' components clarification ---
49	  it.todo("quote for 2 runes + 1 moonstone returns base premium 75 G — no block since types differ (75 + 8 first-insurance + 5 fee = 88 G)");
50	  it.todo("quote for 3 runes + 3 moonstones returns base premium 120 G — two separate blocks (120 + 12 first-insurance + 5 fee = 137 G)");
51	
52	  // --- Item-specific modifier: cursed (applies to that item only) ---
53	  it.todo("quote for cursed sword + plain amulet (newcomer) returns policy base 160 G + 50 G curse on the sword's 100 G base, then first-insurance and fee");
54	
55	  // --- Modifier thresholds ---
56	  it.todo("quote for sword with enchantment exactly 5 applies high-enchantment surcharge (30 % of base premium)");
57	  it.todo("quote for sword with enchantment 4 does NOT apply high-enchantment surcharge");
58	  it.todo("quote for cursed sword with enchantment exactly 5 applies both cursed and high-enchantment surcharges");
59	  it.todo("quote with customer who has exactly 2 years with MHPCO applies the 20 % loyalty discount");
60	
61	  // --- Integration: newcomer with a cursed sword (spec example) ---
62	  it.todo("integration: newcomer (0 years, first contract) cursed sword (steel, enchantment 3) returns premium 165 G");
63	
64	  // --- Integration: long-standing customer's second contract (spec example) ---
65	  it.todo("integration: 3-years customer, 2nd quote in scenario, cursed sword (steel, enchantment 7) returns premium 160 G (loyalty + follow-up + curse + high enchantment + first-insurance per item + fee)");
66	
67	  // --- Rounding in MHPCO's favor ---
68	  it.todo("premium calculation that yields 197.5 G is rounded UP to 198 G");
69	  it.todo("payout calculation that yields 350.5 G is rounded DOWN to 350 G");
70	
71	  // --- Claim: standard reimbursement (no special clauses) ---
72	  it.todo("claim on plain steel sword (enchantment 3) with 500 G damage: payout 400 G (full minus 100 G deductible)");
73	  it.todo("claim on a rune (insurance value 250 G) with 200 G damage: payout 100 G (full minus 100 G deductible; runes have no enchantment/material clauses)");
74	
75	  // --- Claim: high-enchantment clause ---
76	  it.todo("claim on steel sword, enchantment 9, damage 1000 G: payout 400 G (50 % first, then deductible)");
77	
78	  // --- Claim: dragon-material clause ---
79	  it.todo("claim on dragon-material sword, enchantment 5, damage 800 G: payout 700 G (full reimbursement, then deductible)");
80	
81	  // --- Claim: both clauses — 50 % rule wins ---
82	  it.todo("claim on dragon-material sword, enchantment 9, damage 1000 G: payout 400 G (50 % rule wins, then deductible: 500 − 100)");
83	  it.todo("claim on dragon-material sword, enchantment exactly 8, damage 1000 G: payout 400 G (high-enchantment clause applies, then deductible)");
84	
85	  // --- Claim: deductible per damage event (multi-item single incident) ---
86	  it.todo("claim on sword and amulet (single dragon attack), damages [500, 300]: payout 600 G (deductible applies once per damaged item)");
87	
88	  // --- Claim: cap = 2 × insurance sum ---
89	  it.todo("policy with sword and amulet has insurance sum 1600 G; cap is 3200 G");
90	  it.todo("policy with cursed sword (modifiers make premium 165 G) has cap 2000 G — modifiers do not raise the cap");
91	  it.todo("policy with sword and 3 runes (block) has insurance sum 1750 G — block discount affects premium only, not the insurance sum");
92	
93	  // --- Claim: cap exhaustion across successive claims ---
94	  it.todo("sword policy (cap 2000 G), first claim 1500 G: payout 1400 G, remainingCap 600 G");
95	  it.todo("sword policy (cap 2000 G), second successive claim 1500 G: payout 600 G, remainingCap 0 G (reduced to remaining cap)");
96	
97	  // --- Claim: multiple items of the same type ---
98	  it.todo("policy with two swords has insurance sum 2000 G and cap 4000 G");
99	  it.todo("claim on two swords (two separate damage entries) treats each entry as separate damage with its own deductible");
100	  it.todo("claim contains more entries of a given type than the policy covers: the whole claim is rejected (error)");
101	
102	  // --- Edge cases / errors ---
103	  it.todo("quote includes an item with unknown type (e.g. broomstick): error, no results");
104	  it.todo("claim references an item not part of the policy (e.g. amulet damage when only a sword is insured): error");
105	  it.todo("claim with a negative damage amount (amount: -200): error");
106	});
